import { useVoiceRecording } from "@/shared/hooks/useVoiceRecording";

type UseAgentVoiceOptions = {
  onTranscription: (text: string) => void;
  onError?: (error: string) => void;
};

export function useAgentVoice({ onTranscription, onError }: UseAgentVoiceOptions) {
  const {
    startRecording,
    stopRecording,
    toggleRecording,
    isRecording,
    isProcessing,
    audioLevel,
    remainingSeconds,
  } = useVoiceRecording({
    task: "transcribe_only",
    onError,
    onResult: ({ transcription }) => {
      onTranscription(transcription);
    },
  });

  return {
    startRecording,
    stopRecording,
    toggleRecording,
    isRecording,
    isProcessing,
    audioLevel,
    remainingSeconds,
  };
}

export type AgentSessionStatus =
  | "waiting_user"
  | "processing"
  | "continue"
  | "done"
  | "cancelled"
  | "error";

export type AgentTurn = {
  role: "user" | "assistant" | "tool_call" | "tool_result";
  content: string;
  tool_name?: string;
  tool_args?: Record<string, unknown>;
  timestamp: string;
};

export type AgentSession = {
  id: string;
  timeline_id: string;
  user_id: string;
  status: AgentSessionStatus;
  turns: AgentTurn[];
  model: string;
  summary: string | null;
  created_at: string;
  updated_at: string;
};

import Groq from "npm:groq-sdk@0.26.0";

let groqClient: Groq | null = null;

export function getGroqClient(): Groq {
  if (groqClient) {
    return groqClient;
  }

  const apiKey = Deno.env.get("GROQ_API_KEY");
  if (!apiKey) {
    throw new Error("[ai-voice-prompt] Missing Groq provider configuration");
  }

  groqClient = new Groq({ apiKey });
  return groqClient;
}

export async function transcribeAudio(groq: Groq, audioFile: File): Promise<string> {
  const transcription = await groq.audio.transcriptions.create({
    file: audioFile,
    model: "whisper-large-v3-turbo",
    temperature: 0,
    response_format: "verbose_json",
  });

  return transcription.text?.trim() || "";
}

