import { useCallback, useEffect, useLayoutEffect, useRef, useState, type MutableRefObject } from 'react';
import { useMutation } from '@tanstack/react-query';
import { useVideoEditorRuntime } from '@/tools/video-editor/contexts/DataProviderContext';
import type { DataProvider } from '@/tools/video-editor/data/DataProvider';
import { buildTrackClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { getConfigSignature } from '@/tools/video-editor/lib/config-utils';
import { serializeForDisk } from '@/tools/video-editor/lib/serialize';
import { buildDataFromCurrentRegistry, shouldAcceptPolledData } from '@/tools/video-editor/lib/timeline-save-utils';
import { buildTimelineData, configToRows, preserveUploadingClips, rowsToConfig, type ClipMeta, type ClipOrderMap, type TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TimelineRow } from '@/tools/video-editor/types/timeline-canvas';
import type { AssetRegistryEntry, TimelineConfig } from '@/tools/video-editor/types';
export type SaveStatus = 'saved' | 'saving' | 'dirty' | 'error';
export { shouldAcceptPolledData } from '@/tools/video-editor/lib/timeline-save-utils';
interface UseTimelineSaveQueries { timelineQuery: { data: TimelineData | undefined; isLoading: boolean }; assetRegistryQuery: { data: Awaited<ReturnType<DataProvider['loadAssetRegistry']>> | undefined } }
export function useTimelineSave({ timelineQuery, assetRegistryQuery }: UseTimelineSaveQueries, provider: DataProvider, onSaveSuccessRef: MutableRefObject<(() => void) | null>) {
  const { timelineId } = useVideoEditorRuntime();
  const saveTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const lastSavedSignature = useRef('');
  const editSeqRef = useRef(0);
  const savedSeqRef = useRef(0);
  const dataRef = useRef<TimelineData | null>(null);
  const lastRegistryDataRef = useRef<Awaited<ReturnType<typeof provider.loadAssetRegistry>> | null>(null);
  const selectedClipIdRef = useRef<string | null>(null);
  const selectedTrackIdRef = useRef<string | null>(null);
  const [data, setData] = useState<TimelineData | null>(null);
  const [selectedClipId, setSelectedClipId] = useState<string | null>(null);
  const [selectedTrackId, setSelectedTrackId] = useState<string | null>(null);
  const [saveStatus, setSaveStatus] = useState<SaveStatus>('saved');
  useLayoutEffect(() => {
    dataRef.current = data;
    selectedClipIdRef.current = selectedClipId;
    selectedTrackIdRef.current = selectedTrackId;
  }, [data, selectedClipId, selectedTrackId]);
  const saveMutation = useMutation({ mutationFn: (config: TimelineConfig) => provider.saveTimeline(timelineId, config), onError: () => {
    setSaveStatus('error');
    if (dataRef.current) scheduleSave(dataRef.current, { preserveStatus: true });
  } });
  const materializeData = useCallback((current: TimelineData, rows: TimelineRow[], meta: Record<string, ClipMeta>, clipOrder: ClipOrderMap) => {
    const config = rowsToConfig(rows, meta, current.output, clipOrder, current.tracks, current.config.customEffects);
    return preserveUploadingClips({ ...current, rows, meta } as TimelineData, buildDataFromCurrentRegistry(config, current));
  }, []);
  const saveTimeline = useCallback(async (nextData: TimelineData, seq: number) => {
    setSaveStatus('saving');
    await saveMutation.mutateAsync(nextData.config, {
      onSuccess: () => {
        if (seq > savedSeqRef.current) {
          savedSeqRef.current = seq;
          lastSavedSignature.current = nextData.signature;
        }
        setSaveStatus(seq >= editSeqRef.current ? 'saved' : 'dirty');
        onSaveSuccessRef.current?.();
      },
    });
  }, [onSaveSuccessRef, saveMutation]);
  const scheduleSave = useCallback((nextData: TimelineData, options?: { preserveStatus?: boolean }) => {
    if (!options?.preserveStatus) setSaveStatus('dirty');
    if (saveTimer.current) clearTimeout(saveTimer.current);
    saveTimer.current = setTimeout(() => {
      saveTimer.current = null;
      void saveTimeline(nextData, editSeqRef.current);
    }, 500);
  }, [saveTimeline]);
  const commitData = useCallback((nextData: TimelineData, options?: { save?: boolean; selectedClipId?: string | null; selectedTrackId?: string | null; updateLastSavedSignature?: boolean }) => {
    dataRef.current = nextData;
    setData(nextData);
    if (options?.selectedClipId !== undefined) {
      selectedClipIdRef.current = options.selectedClipId;
      setSelectedClipId(options.selectedClipId);
    } else if (selectedClipIdRef.current && !nextData.meta[selectedClipIdRef.current]) {
      selectedClipIdRef.current = null;
      setSelectedClipId(null);
    }
    if (options?.selectedTrackId !== undefined) {
      selectedTrackIdRef.current = options.selectedTrackId;
      setSelectedTrackId(options.selectedTrackId);
    } else {
      const fallbackTrackId = selectedTrackIdRef.current && nextData.tracks.some((track) => track.id === selectedTrackIdRef.current)
        ? selectedTrackIdRef.current
        : nextData.tracks[0]?.id ?? null;
      selectedTrackIdRef.current = fallbackTrackId;
      setSelectedTrackId(fallbackTrackId);
    }
    if (options?.updateLastSavedSignature) lastSavedSignature.current = nextData.signature;
    if (options?.save ?? true) {
      editSeqRef.current += 1;
      scheduleSave(nextData);
    }
  }, [scheduleSave]);
  const applyTimelineEdit = useCallback((nextRows: TimelineRow[], metaUpdates?: Record<string, Partial<ClipMeta>>, metaDeletes?: string[], clipOrderOverride?: ClipOrderMap, options?: { save?: boolean }) => {
    const current = dataRef.current;
    if (!current) return;
    const nextMeta: Record<string, ClipMeta> = { ...current.meta };
    if (metaUpdates) for (const [clipId, patch] of Object.entries(metaUpdates)) nextMeta[clipId] = nextMeta[clipId] ? { ...nextMeta[clipId], ...patch } : (patch as ClipMeta);
    if (metaDeletes) for (const clipId of metaDeletes) delete nextMeta[clipId];
    commitData(materializeData(current, nextRows, nextMeta, clipOrderOverride ?? buildTrackClipOrder(current.tracks, current.clipOrder, metaDeletes)), { save: options?.save });
  }, [commitData, materializeData]);
  const applyResolvedConfigEdit = useCallback((nextResolvedConfig: TimelineData['resolvedConfig'], options?: { selectedClipId?: string | null; selectedTrackId?: string | null }) => {
    const current = dataRef.current;
    if (!current) return;
    commitData(preserveUploadingClips(current, buildDataFromCurrentRegistry(serializeForDisk(nextResolvedConfig), current)), { selectedClipId: options?.selectedClipId, selectedTrackId: options?.selectedTrackId });
  }, [commitData]);
  const patchRegistry = useCallback((assetId: string, entry: AssetRegistryEntry, src?: string) => {
    const current = dataRef.current;
    if (!current) return;
    const nextRegistry = { ...current.registry, assets: { ...current.registry.assets, [assetId]: entry } };
    const nextResolvedRegistry = { ...current.resolvedConfig.registry, [assetId]: { ...entry, src: src ?? current.resolvedConfig.registry[assetId]?.src ?? entry.file } };
    const nextConfig = { ...current.config, customEffects: current.config.customEffects ? { ...current.config.customEffects } : undefined };
    const rowData = configToRows(nextConfig);
    const nextData: TimelineData = {
      ...current,
      config: nextConfig,
      registry: nextRegistry,
      resolvedConfig: {
        ...current.resolvedConfig,
        registry: nextResolvedRegistry,
        clips: current.resolvedConfig.clips.map((clip) => ({ ...clip, assetEntry: clip.asset ? nextResolvedRegistry[clip.asset] : undefined })),
      },
      rows: rowData.rows,
      meta: rowData.meta,
      effects: rowData.effects,
      assetMap: Object.fromEntries(Object.entries(nextRegistry.assets ?? {}).map(([nextAssetId, nextEntry]) => [nextAssetId, nextEntry.file])),
      clipOrder: rowData.clipOrder,
      signature: current.signature,
    };
    nextData.signature = getConfigSignature(nextData.resolvedConfig);
    commitData(nextData, { save: false, selectedClipId: selectedClipIdRef.current, selectedTrackId: selectedTrackIdRef.current });
  }, [commitData]);
  const commitDataRef = useRef(commitData);
  useLayoutEffect(() => {
    commitDataRef.current = commitData;
  }, [commitData]);
  useEffect(() => {
    const polledData = timelineQuery.data;
    if (!polledData || !shouldAcceptPolledData(editSeqRef.current, savedSeqRef.current, polledData.signature, lastSavedSignature.current)) return;
    const syncHandle = window.setTimeout(() => {
      if (!shouldAcceptPolledData(editSeqRef.current, savedSeqRef.current, polledData.signature, lastSavedSignature.current)) return;
      commitDataRef.current(dataRef.current ? preserveUploadingClips(dataRef.current, polledData) : polledData, { save: false, updateLastSavedSignature: true });
    }, 0);
    return () => window.clearTimeout(syncHandle);
  }, [timelineQuery.data]);
  useEffect(() => {
    const current = dataRef.current;
    const registry = assetRegistryQuery.data;
    if (!current || !registry || savedSeqRef.current < editSeqRef.current || registry === lastRegistryDataRef.current) return;
    lastRegistryDataRef.current = registry;
    void buildTimelineData(current.config, registry, (file) => provider.resolveAssetUrl(file)).then((nextData) => {
      if (nextData.signature === current.signature && Object.keys(nextData.assetMap).length === Object.keys(current.assetMap).length) return;
      const syncHandle = window.setTimeout(() => {
        if (savedSeqRef.current < editSeqRef.current) return;
        commitDataRef.current(nextData, { save: false, selectedClipId: selectedClipIdRef.current, selectedTrackId: selectedTrackIdRef.current });
      }, 0);
      return () => window.clearTimeout(syncHandle);
    });
  }, [assetRegistryQuery.data, provider]);
  useEffect(() => () => {
    if (saveTimer.current) clearTimeout(saveTimer.current);
  }, []);
  const reloadFromServer = useCallback(async () => {
    const [config, registry] = await Promise.all([provider.loadTimeline(timelineId), provider.loadAssetRegistry(timelineId)]);
    editSeqRef.current = savedSeqRef.current;
    commitData(await buildTimelineData(config, registry, (file) => provider.resolveAssetUrl(file)), { save: false, updateLastSavedSignature: true, selectedClipId: selectedClipIdRef.current, selectedTrackId: selectedTrackIdRef.current });
    setSaveStatus('saved');
  }, [commitData, provider, timelineId]);
  return {
    data,
    dataRef,
    selectedClipId,
    selectedTrackId,
    saveStatus,
    setSelectedClipId,
    setSelectedTrackId,
    applyTimelineEdit,
    applyResolvedConfigEdit,
    patchRegistry,
    commitData,
    reloadFromServer,
    editSeqRef,
    savedSeqRef,
    selectedClipIdRef,
    selectedTrackIdRef,
    isLoading: timelineQuery.isLoading && !data,
  };
}

import { getSupabaseClient } from '@/integrations/supabase/client';
import { generateUUID } from '@/shared/lib/taskCreation/ids';
import { validateSerializedConfig } from '@/tools/video-editor/lib/serialize';
import { createDefaultTimelineConfig } from '@/tools/video-editor/lib/defaults';
import { extractAssetRegistryEntry } from '@/tools/video-editor/lib/mediaMetadata';
import type { DataProvider, UploadAssetOptions } from '@/tools/video-editor/data/DataProvider';
import type { AssetRegistry, AssetRegistryEntry, TimelineConfig } from '@/tools/video-editor/types';

const TIMELINE_ASSETS_BUCKET = 'timeline-assets';

export class SupabaseDataProvider implements DataProvider {
  constructor(
    private readonly options: {
      projectId: string;
      userId: string;
    },
  ) {}

  async loadTimeline(timelineId: string): Promise<TimelineConfig> {
    const { data, error } = await getSupabaseClient()
      .from('timelines')
      .select('config')
      .eq('id', timelineId)
      .eq('project_id', this.options.projectId)
      .eq('user_id', this.options.userId)
      .single();

    if (error) {
      throw error;
    }

    const config = (data?.config ?? createDefaultTimelineConfig()) as TimelineConfig;
    validateSerializedConfig(config);
    return config;
  }

  async saveTimeline(timelineId: string, config: TimelineConfig): Promise<void> {
    validateSerializedConfig(config);

    const { error } = await getSupabaseClient()
      .from('timelines')
      .update({
        config,
        updated_at: new Date().toISOString(),
      })
      .eq('id', timelineId)
      .eq('project_id', this.options.projectId)
      .eq('user_id', this.options.userId);

    if (error) {
      throw error;
    }
  }

  async loadAssetRegistry(timelineId: string): Promise<AssetRegistry> {
    const { data, error } = await getSupabaseClient()
      .from('timelines')
      .select('asset_registry')
      .eq('id', timelineId)
      .eq('project_id', this.options.projectId)
      .eq('user_id', this.options.userId)
      .single();

    if (error) {
      throw error;
    }

    return (data?.asset_registry as AssetRegistry | null) ?? { assets: {} };
  }

  async resolveAssetUrl(file: string): Promise<string> {
    if (/^https?:\/\//.test(file)) {
      return file;
    }

    const { data, error } = await getSupabaseClient()
      .storage
      .from(TIMELINE_ASSETS_BUCKET)
      .createSignedUrl(file, 60 * 60);

    if (error) {
      throw error;
    }

    return data.signedUrl;
  }

  async registerAsset(
    timelineId: string,
    assetId: string,
    entry: AssetRegistryEntry,
  ): Promise<void> {
    const registry = await this.loadAssetRegistry(timelineId);

    const { error: updateError } = await getSupabaseClient()
      .from('timelines')
      .update({
        asset_registry: {
          assets: {
            ...(registry.assets ?? {}),
            [assetId]: entry,
          },
        },
        updated_at: new Date().toISOString(),
      })
      .eq('id', timelineId)
      .eq('project_id', this.options.projectId)
      .eq('user_id', this.options.userId);

    if (updateError) {
      throw updateError;
    }
  }

  async uploadAsset(
    file: File,
    options: UploadAssetOptions,
  ): Promise<{ assetId: string; entry: Awaited<ReturnType<typeof extractAssetRegistryEntry>> }> {
    const safeFilename = (options.filename ?? file.name)
      .replace(/\s+/g, '-')
      .replace(/[^a-zA-Z0-9._-]/g, '');
    const storagePath = `${options.userId}/${options.timelineId}/${Date.now()}-${safeFilename}`;

    const { error: uploadError } = await getSupabaseClient()
      .storage
      .from(TIMELINE_ASSETS_BUCKET)
      .upload(storagePath, file, {
        upsert: false,
        contentType: file.type || undefined,
      });

    if (uploadError) {
      throw uploadError;
    }

    const entry = await extractAssetRegistryEntry(file, storagePath);
    const assetId = generateUUID();
    await this.registerAsset(options.timelineId, assetId, entry);

    return { assetId, entry };
  }

  async loadWaveform(): Promise<null> {
    return null;
  }

  async loadAssetProfile(): Promise<null> {
    return null;
  }
}

import {
  authenticateRequest,
  type AuthOptions,
  type AuthResult,
} from './auth.ts';
import {
  edgeErrorResponse,
  initEdgeRuntime,
  operationFailureResponse,
  parseJsonBody,
  parseJsonBodyStrict,
  parseJsonFailureResponse,
  type EdgeRuntime,
  type InitEdgeRuntimeOptions,
} from './edgeRequest.ts';
import { jsonResponse } from './http.ts';
import { toErrorMessage } from './errorMessage.ts';

type BodyParseMode = 'none' | 'strict' | 'loose';
type ErrorResponseFormat = 'json' | 'text';

/**
 * Shared runtime options that disable Supabase auth session management.
 * Use in edge functions that handle their own auth (PAT, JWT, service-role).
 */
export const NO_SESSION_RUNTIME_OPTIONS: Pick<EdgeBootstrapOptions, 'runtimeOptions'> = {
  runtimeOptions: {
    clientOptions: {
      auth: {
        autoRefreshToken: false,
        persistSession: false,
      },
    },
  },
} as const;

export interface EdgeBootstrapOptions {
  functionName: string;
  logPrefix: string;
  method?: string;
  parseBody?: BodyParseMode;
  corsPreflight?: boolean;
  errorResponseFormat?: ErrorResponseFormat;
  invalidJsonMessage?: string;
  invalidJsonShapeMessage?: string;
  auth?: {
    required?: boolean;
    requireServiceRole?: boolean;
    options?: AuthOptions;
  };
  runtimeOptions?: InitEdgeRuntimeOptions;
}

export interface EdgeRequestContext<TBody extends Record<string, unknown>> {
  req: Request;
  body: TBody;
  supabaseAdmin: EdgeRuntime['supabaseAdmin'];
  logger: EdgeRuntime['logger'];
  auth: AuthResult | null;
}

type EdgeBootstrapResult<TBody extends Record<string, unknown>> =
  | { ok: true; value: EdgeRequestContext<TBody> }
  | { ok: false; response: Response };

function deriveErrorCode(message: string, status: number): string {
  const normalized = message.trim().toLowerCase();
  if (normalized === 'method not allowed' || status === 405) {
    return 'method_not_allowed';
  }
  if (normalized === 'authentication failed' || status === 401) {
    return 'authentication_failed';
  }
  if (
    normalized === 'unauthorized - service role required'
    || (normalized.includes('unauthorized') && normalized.includes('service role'))
  ) {
    return 'service_role_required';
  }
  if (normalized === 'internal server error' || status >= 500) {
    return 'internal_server_error';
  }
  if (status === 403) {
    return 'forbidden';
  }
  return 'request_failed';
}

function isRecoverableStatus(status: number): boolean {
  return status >= 500 || status === 429;
}

function buildErrorResponse(
  message: string,
  status: number,
  format: ErrorResponseFormat,
  extraHeaders?: Record<string, string>,
): Response {
  if (format === 'text') {
    return new Response(message, {
      status,
      headers: extraHeaders,
    });
  }
  return edgeErrorResponse(
    {
      errorCode: deriveErrorCode(message, status),
      message,
      recoverable: isRecoverableStatus(status),
    },
    status,
    extraHeaders,
  );
}

function parseMode(options: EdgeBootstrapOptions): BodyParseMode {
  return options.parseBody ?? 'none';
}

function methodFor(options: EdgeBootstrapOptions): string {
  return options.method ?? 'POST';
}

function authIsRequired(options: EdgeBootstrapOptions): boolean {
  return options.auth?.required ?? true;
}

function errorFormat(options: EdgeBootstrapOptions): ErrorResponseFormat {
  return options.errorResponseFormat ?? 'json';
}

/**
 * Shared bootstrap for edge handlers:
 * - OPTIONS short-circuit
 * - method guard
 * - runtime initialization
 * - optional JSON body parsing
 * - optional authentication + service-role policy
 */
export async function bootstrapEdgeHandler<TBody extends Record<string, unknown> = Record<string, unknown>>(
  req: Request,
  options: EdgeBootstrapOptions,
): Promise<EdgeBootstrapResult<TBody>> {
  const method = methodFor(options);
  const format = errorFormat(options);
  const corsPreflight = options.corsPreflight ?? true;

  if (corsPreflight && req.method === 'OPTIONS') {
    return {
      ok: false,
      response: jsonResponse({ ok: true }),
    };
  }

  const runtimeResult = initEdgeRuntime(
    options.functionName,
    options.logPrefix,
    options.runtimeOptions,
  );
  if (!runtimeResult.ok) {
    return {
      ok: false,
      response: operationFailureResponse(runtimeResult, 500),
    };
  }

  const { supabaseAdmin, logger } = runtimeResult.value;

  if (req.method !== method) {
    logger.warn('Method not allowed', { method: req.method });
    await logger.flush();
    return {
      ok: false,
      response: buildErrorResponse('Method not allowed', 405, format, { Allow: method }),
    };
  }

  let body: Record<string, unknown> = {};

  if (parseMode(options) === 'strict') {
    const parsedBody = await parseJsonBodyStrict(req, logger, {
      message: options.invalidJsonMessage,
      nonObjectMessage: options.invalidJsonShapeMessage,
    });
    if (!parsedBody.ok) {
      return {
        ok: false,
        response: format === 'text'
          ? buildErrorResponse(parsedBody.message, 400, 'text')
          : parseJsonFailureResponse(parsedBody),
      };
    }
    body = parsedBody.value;
  } else if (parseMode(options) === 'loose') {
    const parsedBody = await parseJsonBody(req, logger, {
      mode: 'loose',
      message: options.invalidJsonMessage,
      nonObjectMessage: options.invalidJsonShapeMessage,
    });
    if (!parsedBody.ok) {
      return {
        ok: false,
        response: format === 'text'
          ? buildErrorResponse(parsedBody.message, 400, 'text')
          : parseJsonFailureResponse(parsedBody),
      };
    }
    body = parsedBody.value;
  }

  let auth: AuthResult | null = null;
  if (authIsRequired(options)) {
    auth = await authenticateRequest(
      req,
      supabaseAdmin,
      options.logPrefix,
      options.auth?.options ?? {},
    );
    if (!auth.success) {
      return {
        ok: false,
        response: buildErrorResponse(
          auth.error || 'Authentication failed',
          auth.statusCode || 401,
          format,
        ),
      };
    }

    if (options.auth?.requireServiceRole && !auth.isServiceRole) {
      return {
        ok: false,
        response: buildErrorResponse('Unauthorized - service role required', 403, format),
      };
    }
  }

  return {
    ok: true,
    value: {
      req,
      body: body as TBody,
      supabaseAdmin,
      logger,
      auth,
    },
  };
}

/**
 * High-level request wrapper that standardizes edge endpoint choreography:
 * bootstrap -> handler -> unified unexpected-error response -> guaranteed flush.
 */
export async function withEdgeRequest<TBody extends Record<string, unknown> = Record<string, unknown>>(
  req: Request,
  options: EdgeBootstrapOptions,
  handler: (context: EdgeRequestContext<TBody>) => Promise<Response>,
): Promise<Response> {
  const bootstrap = await bootstrapEdgeHandler<TBody>(req, options);
  if (!bootstrap.ok) {
    return bootstrap.response;
  }

  const context = bootstrap.value;
  try {
    return await handler(context);
  } catch (error: unknown) {
    context.logger.critical('Unexpected error', {
      error: toErrorMessage(error),
    });
    return buildErrorResponse('Internal server error', 500, errorFormat(options));
  } finally {
    await context.logger.flush();
  }
}

import { getSupabasePublishableKey, getSupabaseUrl } from '@/integrations/supabase/config/env';
import { isAbortError } from '@/shared/lib/errorHandling/errorUtils';
import { normalizeAndPresentAndRethrow } from '@/shared/lib/errorHandling/runtimeError';
import { AuthError, NetworkError, ServerError } from '@/shared/lib/errorHandling/errors';
import { readAccessTokenFromStorage } from '@/shared/lib/supabaseSession';
import { generateUUID } from './ids';
import { parseTaskCreationResponse } from './parseTaskCreationResponse';
import type { BaseTaskParams, TaskCreationResult } from './types';

/**
 * Creates a task using the unified create-task edge function.
 */
export async function createTask(taskParams: BaseTaskParams): Promise<TaskCreationResult> {
  // Read access token from localStorage — avoids navigator.locks contention.
  // getSession() acquires a shared navigator.lock blocked during token refresh.
  const accessToken = readAccessTokenFromStorage();

  if (!accessToken) {
    throw new AuthError('Please log in to create tasks', { needsLogin: true });
  }

  const startTime = Date.now();
  const requestId = `${startTime}-${Math.random().toString(36).slice(2, 8)}`;
  const requestContext = {
    requestId,
    taskType: taskParams.task_type,
    projectId: taskParams.project_id,
  };
  const timeoutMs = 20000; // 20s safety timeout to avoid indefinite UI stall
  const controller = new AbortController();
  const timeout = setTimeout(() => {
    controller.abort();
  }, timeoutMs);

  try {
    // Generate an idempotency key to prevent duplicate task creation from
    // network retries or double-clicks. The server will return the existing
    // task if this key was already used.
    const idempotency_key = generateUUID();

    const response = await fetch(`${getSupabaseUrl()}/functions/v1/create-task`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${accessToken}`,
        apikey: getSupabasePublishableKey(),
      },
      body: JSON.stringify({
        params: taskParams.params,
        task_type: taskParams.task_type,
        project_id: taskParams.project_id,
        dependant_on: null,
        idempotency_key,
      }),
      signal: controller.signal,
    });

    if (!response.ok) {
      const errorText = await response.text().catch(() => '');
      throw new ServerError(errorText || 'Failed to create task', {
        context: requestContext,
      });
    }

    const data = await response.json() as unknown;
    return parseTaskCreationResponse(data, requestContext);
  } catch (err: unknown) {
    const context = {
      requestId,
      taskType: taskParams.task_type,
      projectId: taskParams.project_id,
      durationMs: Date.now() - startTime,
    };

    if (import.meta.env.DEV) {
      console.error('[createTask] invoke FAILED', context, err);
    }

    // Normalize abort errors for better UX
    if (isAbortError(err)) {
      throw new NetworkError('Task creation timed out. Please try again.', {
        isTimeout: true,
        context,
        cause: err instanceof Error ? err : undefined,
      });
    }

    normalizeAndPresentAndRethrow(err, {
      context: 'TaskCreation',
      showToast: false,
      logData: context,
    });
  } finally {
    clearTimeout(timeout);
  }
}

import { useCallback, useEffect, useState } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { realtimeEventProcessor } from '@/shared/realtime/RealtimeEventProcessor';
import { assetRegistryQueryKey, timelineQueryKey } from '@/tools/video-editor/hooks/useTimeline';
import { timelineListQueryKey } from '@/tools/video-editor/hooks/useTimelinesList';

interface UseTimelineRealtimeOptions {
  timelineId: string;
  saveStatus: 'saved' | 'saving' | 'dirty' | 'error';
  onDiscardRemoteChanges: () => Promise<void>;
}

export function useTimelineRealtime({
  timelineId,
  saveStatus,
  onDiscardRemoteChanges,
}: UseTimelineRealtimeOptions) {
  const queryClient = useQueryClient();
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    return realtimeEventProcessor.onEvent((event) => {
      if (event.type !== 'timelines-updated') {
        return;
      }

      const matching = event.timelines.find((timeline) => timeline.id === timelineId);
      if (!matching) {
        return;
      }

      if (saveStatus !== 'saved') {
        setIsOpen(true);
        return;
      }

      void queryClient.invalidateQueries({ queryKey: timelineQueryKey(timelineId) });
      void queryClient.invalidateQueries({ queryKey: assetRegistryQueryKey(timelineId) });
      void queryClient.invalidateQueries({ queryKey: timelineListQueryKey(matching.projectId) });
    });
  }, [queryClient, saveStatus, timelineId]);

  const keepLocalChanges = useCallback(() => setIsOpen(false), []);

  const discardAndReload = useCallback(async () => {
    setIsOpen(false);
    await onDiscardRemoteChanges();
    await Promise.all([
      queryClient.invalidateQueries({ queryKey: timelineQueryKey(timelineId) }),
      queryClient.invalidateQueries({ queryKey: assetRegistryQueryKey(timelineId) }),
    ]);
  }, [onDiscardRemoteChanges, queryClient, timelineId]);

  return {
    isOpen,
    setOpen: setIsOpen,
    keepLocalChanges,
    discardAndReload,
  };
}

