  const assetRegistryQuery = useQuery({
    queryKey: assetRegistryQueryKey(timelineId),
    enabled: Boolean(timelineId),
    queryFn: () => provider.loadAssetRegistry(timelineId),
    refetchInterval: 30_000,
  });

  return {
    timelineQuery,
    assetRegistryQuery,
  };
}

