import { serve } from "https://deno.land/std@0.224.0/http/server.ts";
import { NO_SESSION_RUNTIME_OPTIONS, withEdgeRequest } from "../_shared/edgeHandler.ts";
import { jsonResponse } from "../_shared/http.ts";
import { TIMELINE_AGENT_TOOLS } from "./tools.ts";
import type {
  AgentSession,
  AgentSessionStatus,
  AgentTurn,
} from "../../../src/tools/video-editor/types/agent-session.ts";

interface AgentInvocationBody {
  session_id?: unknown;
  user_message?: unknown;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function isSessionStatus(value: unknown): value is AgentSessionStatus {
  return value === "waiting_user"
    || value === "processing"
    || value === "continue"
    || value === "done"
    || value === "cancelled"
    || value === "error";
}

function normalizeTurns(value: unknown): AgentTurn[] {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.flatMap((item) => {
    if (!isRecord(item) || typeof item.content !== "string" || typeof item.timestamp !== "string") {
      return [];
    }

    const role = item.role;
    if (role !== "user" && role !== "assistant" && role !== "tool_call" && role !== "tool_result") {
      return [];
    }

    return [{
      role,
      content: item.content,
      tool_name: typeof item.tool_name === "string" ? item.tool_name : undefined,
      tool_args: isRecord(item.tool_args) ? item.tool_args : undefined,
      timestamp: item.timestamp,
    }];
  });
}

function createTurn(role: AgentTurn["role"], content: string): AgentTurn {
  return {
    role,
    content,
    timestamp: new Date().toISOString(),
  };
}

function normalizeSessionRow(row: Record<string, unknown>): AgentSession {
  return {
    id: typeof row.id === "string" ? row.id : "",
    timeline_id: typeof row.timeline_id === "string" ? row.timeline_id : "",
    user_id: typeof row.user_id === "string" ? row.user_id : "",
    status: isSessionStatus(row.status) ? row.status : "error",
    turns: normalizeTurns(row.turns),
    model: typeof row.model === "string" ? row.model : "groq",
    summary: typeof row.summary === "string" ? row.summary : null,
    created_at: typeof row.created_at === "string" ? row.created_at : "",
    updated_at: typeof row.updated_at === "string" ? row.updated_at : "",
  };
}

serve((req) => withEdgeRequest<AgentInvocationBody>(
  req,
  {
    functionName: "ai-timeline-agent",
    logPrefix: "[AI-TIMELINE-AGENT]",
    method: "POST",
    parseBody: "strict",
    auth: {
      required: true,
      options: { allowJwtUserAuth: true },
    },
    ...NO_SESSION_RUNTIME_OPTIONS,
  },
  async ({ auth, body, logger, supabaseAdmin }) => {
    if (!auth?.userId) {
      return jsonResponse({ error: "Authentication failed" }, 401);
    }

    const sessionId = typeof body.session_id === "string" ? body.session_id.trim() : "";
    const userMessage = body.user_message === undefined || body.user_message === null
      ? undefined
      : typeof body.user_message === "string"
        ? body.user_message.trim()
        : null;

    if (!sessionId) {
      return jsonResponse({ error: "session_id is required" }, 400);
    }

    if (userMessage === null) {
      return jsonResponse({ error: "user_message must be a string when provided" }, 400);
    }

    const { data: rawSession, error: sessionError } = await supabaseAdmin
      .from("timeline_agent_sessions")
      .select("*")
      .eq("id", sessionId)
      .maybeSingle();

    if (sessionError) {
      logger.error("Failed to load session", {
        session_id: sessionId,
        error: sessionError.message,
      });
      return jsonResponse({ error: "Failed to load session" }, 500);
    }

    if (!rawSession || !isRecord(rawSession)) {
      return jsonResponse({ error: "Session not found" }, 404);
    }

    const session = normalizeSessionRow(rawSession);

    if (session.user_id !== auth.userId) {
      return jsonResponse({ error: "Forbidden" }, 403);
    }

    if (session.status === "cancelled") {
      return jsonResponse({ error: "Session cancelled", status: "cancelled" }, 409);
    }

    const nextTurns = userMessage ? [...session.turns, createTurn("user", userMessage)] : session.turns;
    const nextStatus: AgentSessionStatus = "processing";

    const { error: updateError } = await supabaseAdmin
      .from("timeline_agent_sessions")
      .update({
        status: nextStatus,
        turns: nextTurns,
        updated_at: new Date().toISOString(),
      })
      .eq("id", session.id);

    if (updateError) {
      logger.error("Failed to persist session state", {
        session_id: session.id,
        error: updateError.message,
      });
      return jsonResponse({ error: "Failed to update session" }, 500);
    }

    logger.info("Agent scaffold invocation stored", {
      session_id: session.id,
      status: nextStatus,
      turns_added: userMessage ? 1 : 0,
      tool_count: TIMELINE_AGENT_TOOLS.length,
    });

    return jsonResponse({
      session_id: session.id,
      status: nextStatus,
      turns_added: userMessage ? 1 : 0,
      tool_count: TIMELINE_AGENT_TOOLS.length,
      model: session.model,
    });
  },
));

