const JSON_HEADERS = {
  "Content-Type": "application/json",
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Methods": "POST, OPTIONS",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

export function jsonResponse(body: unknown, status = 200): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: JSON_HEADERS,
  });
}

// deno-lint-ignore-file
import { serve } from "https://deno.land/std@0.224.0/http/server.ts";
import Groq from "npm:groq-sdk@0.26.0";
import {
  enforceRateLimit,
  RATE_LIMITS,
} from "../_shared/rateLimit.ts";
import { bootstrapEdgeHandler, NO_SESSION_RUNTIME_OPTIONS } from "../_shared/edgeHandler.ts";
import { jsonResponse } from "../_shared/http.ts";
import { toErrorMessage } from "../_shared/errorMessage.ts";
import {
  buildEditPromptMessages,
  buildEnhanceSegmentUserPrompt,
  buildGeneratePromptsMessages,
  ENHANCE_SEGMENT_SYSTEM_PROMPT,
} from "./templates.ts";

const GROQ_MODEL = "moonshotai/kimi-k2-instruct-0905";
const GROQ_FALLBACK_MODEL = "llama-3.3-70b-versatile";
const GROQ_TIMEOUT_MS = 30_000;

let groqClient: Groq | null = null;

function getGroqClient(): Groq {
  if (groqClient) {
    return groqClient;
  }
  const apiKey = Deno.env.get("GROQ_API_KEY");
  if (!apiKey) {
    throw new Error("[ai-prompt] Missing Groq provider configuration");
  }
  groqClient = new Groq({ apiKey, timeout: GROQ_TIMEOUT_MS });
  return groqClient;
}

interface GroqChatParams {
  model: string;
  messages: { role: string; content: string }[];
  temperature: number;
  max_tokens: number;
  top_p?: number;
}

async function groqWithFallback(
  groq: Groq,
  params: GroqChatParams,
  logger: { info: (msg: string) => void },
) {
  try {
    return await groq.chat.completions.create(params as Parameters<typeof groq.chat.completions.create>[0]);
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err);
    const isModelError = msg.includes("model") || msg.includes("timeout") || msg.includes("abort") || msg.includes("could not process");
    if (isModelError && params.model !== GROQ_FALLBACK_MODEL) {
      logger.info(`[AI-PROMPT] Primary model failed (${msg}), falling back to ${GROQ_FALLBACK_MODEL}`);
      return await groq.chat.completions.create({
        ...params,
        model: GROQ_FALLBACK_MODEL,
      } as Parameters<typeof groq.chat.completions.create>[0]);
    }
    throw err;
  }
}

function getOpenAIApiKey(): string {
  const apiKey = Deno.env.get("OPENAI_API_KEY");
  if (!apiKey) {
    throw new Error("[ai-prompt] Missing OpenAI provider configuration");
  }
  return apiKey;
}

serve(async (req) => {
  const bootstrap = await bootstrapEdgeHandler(req, {
    functionName: "ai-prompt",
    logPrefix: "[AI-PROMPT]",
    parseBody: "strict",
    auth: {
      required: true,
      options: { allowJwtUserAuth: true },
    },
    ...NO_SESSION_RUNTIME_OPTIONS,
  });
  if (!bootstrap.ok) {
    return bootstrap.response;
  }

  const { supabaseAdmin, logger, auth, body } = bootstrap.value;
  if (!auth?.userId) {
    return jsonResponse({ error: "Authentication failed" }, 401);
  }

  // Rate limit by user ID (this is an expensive AI endpoint)
  const rateLimitDenied = await enforceRateLimit({
    supabaseAdmin,
    functionName: 'ai-prompt',
    userId: auth.userId,
    config: RATE_LIMITS.expensive,
    logger,
    logPrefix: '[AI-PROMPT]',
    responses: {
      serviceUnavailable: () => jsonResponse({ error: 'Rate limit service unavailable' }, 503),
    },
  });
  if (rateLimitDenied) {
    return rateLimitDenied;
  }

  const task = body.task as string | undefined;
  if (!task) return jsonResponse({ error: "task is required" }, 400);

  try {
    switch (task) {
      case "generate_prompts": {
        const groq = getGroqClient();
        const overallPromptText = String(body.overallPromptText ?? "");
        const rulesToRememberText = String(body.rulesToRememberText ?? "");
        const numberToGenerate = Number(body.numberToGenerate ?? 3);
        const existingPrompts = Array.isArray(body.existingPrompts) ? body.existingPrompts as unknown[] : [];
        const temperature = Number(body.temperature ?? 0.8);

        const { systemMsg, userMsg } = buildGeneratePromptsMessages({
          overallPromptText,
          rulesToRememberText,
          numberToGenerate,
          existingPrompts,
        });

        logger.info(`[AI-PROMPT] generate_prompts: starting Groq call, model=${GROQ_MODEL}, numberToGenerate=${numberToGenerate}`);
        const groqStart = Date.now();
        const resp = await groqWithFallback(groq, {
          model: GROQ_MODEL,
          messages: [
            { role: "system", content: systemMsg },
            { role: "user", content: userMsg },
          ],
          temperature: temperature,
          max_tokens: 4096,
          top_p: 1,
        }, logger);
        logger.info(`[AI-PROMPT] generate_prompts: Groq call completed in ${Date.now() - groqStart}ms, model=${resp.model}`);
        const outputText = resp.choices[0]?.message?.content?.trim() || "";
        const prompts = outputText.split("\n").map((s) => s.trim()).filter(Boolean);

        // Validate we got the expected number of prompts
        if (prompts.length !== numberToGenerate) {
          // If we got too many, take the first N
          if (prompts.length > numberToGenerate) {
            prompts.splice(numberToGenerate);
          }
          // If we got too few, we'll just return what we have rather than failing
        }

        return jsonResponse({ prompts, usage: resp.usage });
      }
      case "edit_prompt": {
        const groq = getGroqClient();
        const originalPromptText = String(body.originalPromptText ?? "");
        const editInstructions = String(body.editInstructions ?? "");
        if (!originalPromptText || !editInstructions) return jsonResponse({ error: "originalPromptText and editInstructions required" }, 400);
        const { systemMsg, userMsg } = buildEditPromptMessages({
          originalPromptText,
          editInstructions,
        });
        const resp = await groqWithFallback(groq, {
          model: GROQ_MODEL,
          messages: [
            { role: "system", content: systemMsg },
            { role: "user", content: userMsg },
          ],
          temperature: 0.7,
          max_tokens: 2048,
          top_p: 1,
        }, logger);
        const newText = resp.choices[0]?.message?.content?.trim() || originalPromptText;
        return jsonResponse({ success: true, newText, usage: resp.usage });
      }
      case "generate_summary": {
        const groq = getGroqClient();
        const promptText = String(body.promptText ?? "");
        if (!promptText) return jsonResponse({ error: "promptText required" }, 400);
        logger.info(`[AI-PROMPT] generate_summary: starting Groq call`);
        const summaryStart = Date.now();
        const resp = await groqWithFallback(groq, {
          model: GROQ_MODEL,
          messages: [{ role: "user", content: `Create a brief summary of this image prompt in 10 words or less. Output only the summary text with no additional formatting or quotation marks:

"${promptText}"

Summary:` }],
          temperature: 1.0,
          max_tokens: 50,
          top_p: 1,
        }, logger);
        logger.info(`[AI-PROMPT] generate_summary: Groq call completed in ${Date.now() - summaryStart}ms`);
        const summary = resp.choices[0]?.message?.content?.trim() || null;
        return jsonResponse({ summary, usage: resp.usage });
      }
      case "enhance_segment_prompt": {
        // Enhance a single segment prompt using OpenAI GPT-5 Mini
        // Uses motion-focused prompt template for video transitions
        const prompt = String(body.prompt ?? "");
        const _temperature = Number(body.temperature ?? 0.7);

        if (!prompt.trim()) {
          return jsonResponse({ error: "prompt is required" }, 400);
        }

        const openaiApiKey = getOpenAIApiKey();

        const systemMsg = ENHANCE_SEGMENT_SYSTEM_PROMPT;
        const userMsg = buildEnhanceSegmentUserPrompt(prompt);

        try {
          const response = await fetch("https://api.openai.com/v1/chat/completions", {
            method: "POST",
            headers: {
              "Authorization": `Bearer ${openaiApiKey}`,
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              model: "gpt-5-mini",
              messages: [
                { role: "system", content: systemMsg },
                { role: "user", content: userMsg },
              ],
              max_completion_tokens: 16000,
            }),
          });

          if (!response.ok) {
            const errorText = await response.text();
            console.error(`[ai-prompt] OpenAI API error:`, response.status, errorText);
            return jsonResponse({ error: "OpenAI API error", details: errorText }, response.status);
          }

          const data = await response.json();

          const enhancedPrompt = data.choices?.[0]?.message?.content?.trim() || prompt;

          return jsonResponse({
            enhanced_prompt: enhancedPrompt,
            usage: data.usage,
          });
        } catch (fetchError: unknown) {
          const message = toErrorMessage(fetchError);
          console.error(`[ai-prompt] OpenAI fetch error:`, message);
          return jsonResponse({ error: "Failed to call OpenAI API", details: message }, 500);
        }
      }
      default:
        return jsonResponse({ error: `Unknown task: ${task}` }, 400);
    }
  } catch (err: unknown) {
    const message = toErrorMessage(err);
    console.error(`[ai-prompt] Error handling task ${task}:`, message);
    return jsonResponse({ error: "Internal server error", details: message }, 500);
  }
});

import { createContext, useContext, ReactNode, useMemo } from 'react';
import { Project } from '@/types/project';
import { useRenderLogger } from '@/shared/lib/debug/debugRendering';
import { useProjectSessionCoordinator } from './useProjectSessionCoordinator';
import { requireContextValue } from './contextGuard';

// Type for updating projects (re-exported for consumers that may need it)
interface ProjectUpdate {
  name?: string;
  aspectRatio?: string;
}

interface ProjectSelectionContextType {
  selectedProjectId: string | null;
  project: Project | null;
  setSelectedProjectId: (projectId: string | null) => void;
}

interface ProjectCrudContextType {
  projects: Project[];
  isLoadingProjects: boolean;
  fetchProjects: () => Promise<void>;
  addNewProject: (projectData: { name: string; aspectRatio: string }) => Promise<Project | null>;
  isCreatingProject: boolean;
  updateProject: (projectId: string, updates: ProjectUpdate) => Promise<boolean>;
  isUpdatingProject: boolean;
  deleteProject: (projectId: string) => Promise<boolean>;
  isDeletingProject: boolean;
}

interface ProjectIdentityContextType {
  /** Current authenticated user ID, null if not logged in */
  userId: string | null;
}

interface ProjectContextType
  extends ProjectSelectionContextType,
    ProjectCrudContextType,
    ProjectIdentityContextType {}

const ProjectSelectionContext = createContext<ProjectSelectionContextType | undefined>(undefined);
const ProjectCrudContext = createContext<ProjectCrudContextType | undefined>(undefined);
const ProjectIdentityContext = createContext<ProjectIdentityContextType | undefined>(undefined);

export const ProjectProvider = ({ children }: { children: ReactNode }) => {
  const { userId, selection, crud } = useProjectSessionCoordinator();
  useRenderLogger('ProjectProvider', { userId });

  const projects = crud.projects || [];
  const selectedProjectId = selection.selectedProjectId;
  const project = projects.find((item) => item.id === selectedProjectId) ?? null;

  const selectionValue = useMemo(
    (): ProjectSelectionContextType => ({
      selectedProjectId,
      project,
      setSelectedProjectId: selection.setSelectedProjectId,
    }),
    [selectedProjectId, project, selection.setSelectedProjectId],
  );

  const crudValue = useMemo(
    (): ProjectCrudContextType => ({
      projects: crud.projects || [],
      isLoadingProjects: crud.isLoadingProjects,
      fetchProjects: crud.fetchProjects,
      addNewProject: crud.addNewProject,
      isCreatingProject: crud.isCreatingProject,
      updateProject: crud.updateProject,
      isUpdatingProject: crud.isUpdatingProject,
      deleteProject: crud.deleteProject,
      isDeletingProject: crud.isDeletingProject,
    }),
    [
      crud.projects,
      crud.isLoadingProjects,
      crud.fetchProjects,
      crud.addNewProject,
      crud.isCreatingProject,
      crud.updateProject,
      crud.isUpdatingProject,
      crud.deleteProject,
      crud.isDeletingProject,
    ],
  );

  const identityValue = useMemo(
    (): ProjectIdentityContextType => ({
      userId: userId ?? null,
    }),
    [userId],
  );

  return (
    <ProjectIdentityContext.Provider value={identityValue}>
      <ProjectCrudContext.Provider value={crudValue}>
        <ProjectSelectionContext.Provider value={selectionValue}>
          {children}
        </ProjectSelectionContext.Provider>
      </ProjectCrudContext.Provider>
    </ProjectIdentityContext.Provider>
  );
};

export const useProjectSelectionContext = () => {
  return requireContextValue(
    useContext(ProjectSelectionContext),
    'useProjectSelectionContext',
    'ProjectProvider',
  );
};

export const useProjectCrudContext = () => {
  return requireContextValue(
    useContext(ProjectCrudContext),
    'useProjectCrudContext',
    'ProjectProvider',
  );
};

export const useProjectIdentityContext = () => {
  return requireContextValue(
    useContext(ProjectIdentityContext),
    'useProjectIdentityContext',
    'ProjectProvider',
  );
};

/** Compatibility hook for existing callers that still need the combined project contract. */
export const useProject = () => {
  const selection = requireContextValue(
    useContext(ProjectSelectionContext),
    'useProject',
    'ProjectProvider',
  );
  const crud = requireContextValue(
    useContext(ProjectCrudContext),
    'useProject',
    'ProjectProvider',
  );
  const identity = requireContextValue(
    useContext(ProjectIdentityContext),
    'useProject',
    'ProjectProvider',
  );

  return useMemo<ProjectContextType>(() => ({
    ...crud,
    ...selection,
    ...identity,
  }), [crud, selection, identity]);
};

import type {
  AssetRegistry,
  TimelineClip,
  TimelineConfig,
  TrackDefinition,
} from "../../../src/tools/video-editor/types/index.ts";

export interface TimelineToolResult {
  result: string;
  config?: TimelineConfig;
}

type ClipProperty = "volume" | "speed" | "opacity" | "x" | "y" | "width" | "height";

const MUTABLE_CLIP_PROPERTIES: ClipProperty[] = [
  "volume",
  "speed",
  "opacity",
  "x",
  "y",
  "width",
  "height",
];

function roundSeconds(value: number): number {
  return Math.round(value * 1000) / 1000;
}

function cloneConfig(config: TimelineConfig): TimelineConfig {
  return structuredClone(config);
}

function getAssetDuration(registry: AssetRegistry, assetId?: string): number | null {
  if (!assetId) {
    return null;
  }

  const duration = registry.assets?.[assetId]?.duration;
  return typeof duration === "number" ? duration : null;
}

function getClipSourceDuration(clip: TimelineClip, registry: AssetRegistry): number {
  if (typeof clip.hold === "number") {
    return clip.hold;
  }

  if (typeof clip.from === "number" && typeof clip.to === "number") {
    return clip.to - clip.from;
  }

  return getAssetDuration(registry, clip.asset) ?? 0;
}

function getClipTimelineDuration(clip: TimelineClip, registry: AssetRegistry): number {
  const speed = clip.speed ?? 1;
  return getClipSourceDuration(clip, registry) / speed;
}

function formatClipLine(clip: TimelineClip, registry: AssetRegistry): string {
  const duration = roundSeconds(getClipTimelineDuration(clip, registry));
  return [
    `id=${clip.id}`,
    `track=${clip.track}`,
    `at=${roundSeconds(clip.at)}s`,
    `duration=${duration}s`,
    `type=${clip.clipType ?? "media"}`,
    `asset=${clip.asset ?? "none"}`,
  ].join(" | ");
}

function getTrackDefinitions(config: TimelineConfig): TrackDefinition[] {
  if (config.tracks?.length) {
    return config.tracks;
  }

  const inferredTrackIds = Array.from(new Set(config.clips.map((clip) => clip.track)));
  return inferredTrackIds.map((trackId) => ({
    id: trackId,
    label: trackId,
    kind: "visual",
  }));
}

function getClipIndex(config: TimelineConfig, clipId: string): number {
  return config.clips.findIndex((clip) => clip.id === clipId);
}

function describeTimeline(config: TimelineConfig, registry: AssetRegistry): string {
  const tracks = getTrackDefinitions(config);
  const totalDuration = config.clips.reduce((maxDuration, clip) => {
    return Math.max(maxDuration, clip.at + getClipTimelineDuration(clip, registry));
  }, 0);

  const lines = [
    `Timeline summary: ${tracks.length} track(s), ${config.clips.length} clip(s), total duration ${roundSeconds(totalDuration)}s.`,
    "Tracks:",
    ...tracks.map((track) => `- ${track.id} (${track.kind}): ${track.label}`),
    "Clips:",
    ...config.clips.map((clip) => `- ${formatClipLine(clip, registry)}`),
  ];

  return lines.join("\n");
}

export function viewTimeline(config: TimelineConfig, registry: AssetRegistry): TimelineToolResult {
  return {
    result: describeTimeline(config, registry),
  };
}

export function moveClip(
  config: TimelineConfig,
  _registry: AssetRegistry,
  args: { clipId?: string; at?: number },
): TimelineToolResult {
  if (typeof args.clipId !== "string" || typeof args.at !== "number") {
    return { result: "move_clip requires clipId and at." };
  }

  const nextConfig = cloneConfig(config);
  const clipIndex = getClipIndex(nextConfig, args.clipId);
  if (clipIndex < 0) {
    return { result: `Clip ${args.clipId} was not found.` };
  }

  const previousAt = nextConfig.clips[clipIndex].at;
  nextConfig.clips[clipIndex].at = roundSeconds(args.at);

  return {
    config: nextConfig,
    result: `Moved clip ${args.clipId} from ${roundSeconds(previousAt)}s to ${roundSeconds(args.at)}s.`,
  };
}

export function trimClip(
  config: TimelineConfig,
  registry: AssetRegistry,
  args: { clipId?: string; from?: number; to?: number; duration?: number },
): TimelineToolResult {
  if (typeof args.clipId !== "string") {
    return { result: "trim_clip requires clipId." };
  }

  const nextConfig = cloneConfig(config);
  const clipIndex = getClipIndex(nextConfig, args.clipId);
  if (clipIndex < 0) {
    return { result: `Clip ${args.clipId} was not found.` };
  }

  const clip = nextConfig.clips[clipIndex];
  const assetDuration = getAssetDuration(registry, clip.asset);
  const currentFrom = typeof clip.from === "number" ? clip.from : 0;
  const currentTo = typeof clip.to === "number"
    ? clip.to
    : typeof clip.hold === "number"
      ? clip.hold
      : assetDuration ?? 0;

  let nextFrom = typeof args.from === "number" ? args.from : currentFrom;
  let nextTo = typeof args.to === "number" ? args.to : currentTo;

  if (typeof args.duration === "number") {
    if (args.duration <= 0) {
      return { result: "trim_clip duration must be greater than 0." };
    }

    if (typeof args.from === "number") {
      nextTo = args.from + args.duration;
    } else if (typeof args.to === "number") {
      nextFrom = args.to - args.duration;
    } else if (typeof clip.hold === "number" && !clip.asset) {
      clip.hold = roundSeconds(args.duration);
      return {
        config: nextConfig,
        result: `Updated hold duration for clip ${clip.id} to ${roundSeconds(args.duration)}s.`,
      };
    } else {
      nextTo = nextFrom + args.duration;
    }
  }

  if (nextFrom < 0 || nextTo <= nextFrom) {
    return { result: `Invalid trim range for clip ${clip.id}.` };
  }

  if (assetDuration !== null && nextTo > assetDuration + 0.0001) {
    return {
      result: `Trim range for clip ${clip.id} exceeds asset duration ${roundSeconds(assetDuration)}s.`,
    };
  }

  clip.from = roundSeconds(nextFrom);
  clip.to = roundSeconds(nextTo);
  delete clip.hold;

  return {
    config: nextConfig,
    result: `Trimmed clip ${clip.id} to source range ${roundSeconds(nextFrom)}s-${roundSeconds(nextTo)}s.`,
  };
}

export function setClipProperty(
  config: TimelineConfig,
  _registry: AssetRegistry,
  args: { clipId?: string; property?: string; value?: unknown },
): TimelineToolResult {
  if (
    typeof args.clipId !== "string"
    || typeof args.property !== "string"
    || typeof args.value !== "number"
  ) {
    return { result: "set_clip_property requires clipId, property, and numeric value." };
  }

  if (!MUTABLE_CLIP_PROPERTIES.includes(args.property as ClipProperty)) {
    return {
      result: `Property ${args.property} is not allowed. Use one of ${MUTABLE_CLIP_PROPERTIES.join(", ")}.`,
    };
  }

  const nextConfig = cloneConfig(config);
  const clipIndex = getClipIndex(nextConfig, args.clipId);
  if (clipIndex < 0) {
    return { result: `Clip ${args.clipId} was not found.` };
  }

  const clip = nextConfig.clips[clipIndex] as TimelineClip & Record<ClipProperty, number | undefined>;
  const previousValue = clip[args.property as ClipProperty];
  clip[args.property as ClipProperty] = args.value;

  return {
    config: nextConfig,
    result: `Set ${args.property} on clip ${clip.id} from ${previousValue ?? "unset"} to ${args.value}.`,
  };
}

export function deleteClip(
  config: TimelineConfig,
  _registry: AssetRegistry,
  args: { clipId?: string },
): TimelineToolResult {
  if (typeof args.clipId !== "string") {
    return { result: "delete_clip requires clipId." };
  }

  const clip = config.clips.find((item) => item.id === args.clipId);
  if (!clip) {
    return { result: `Clip ${args.clipId} was not found.` };
  }

  const nextConfig = cloneConfig(config);
  nextConfig.clips = nextConfig.clips.filter((item) => item.id !== args.clipId);

  return {
    config: nextConfig,
    result: `Deleted clip ${clip.id} on track ${clip.track}.`,
  };
}

export function addTextClip(
  config: TimelineConfig,
  _registry: AssetRegistry,
  args: { track?: string; at?: number; duration?: number; text?: string },
): TimelineToolResult {
  if (
    typeof args.track !== "string"
    || typeof args.at !== "number"
    || typeof args.duration !== "number"
    || typeof args.text !== "string"
  ) {
    return { result: "add_text_clip requires track, at, duration, and text." };
  }

  if (args.duration <= 0) {
    return { result: "add_text_clip duration must be greater than 0." };
  }

  const tracks = getTrackDefinitions(config);
  if (tracks.length > 0 && !tracks.some((track) => track.id === args.track)) {
    return { result: `Track ${args.track} does not exist.` };
  }

  const nextConfig = cloneConfig(config);
  const clipId = crypto.randomUUID();
  nextConfig.clips.push({
    id: clipId,
    at: roundSeconds(args.at),
    track: args.track,
    clipType: "text",
    hold: roundSeconds(args.duration),
    text: {
      content: args.text,
    },
  });

  return {
    config: nextConfig,
    result: `Added text clip ${clipId} on track ${args.track} at ${roundSeconds(args.at)}s for ${roundSeconds(args.duration)}s.`,
  };
}

export function findIssues(config: TimelineConfig, registry: AssetRegistry): TimelineToolResult {
  const issues: string[] = [];
  const clipsByTrack = new Map<string, TimelineClip[]>();

  for (const clip of config.clips) {
