type RenderedTurn = {
  key: string;
  turn: AgentTurn;
  resultTurn?: AgentTurn | null;
};

function formatSessionLabel(turns: AgentTurn[]) {
  const firstUserTurn = turns.find((turn) => turn.role === 'user');
  if (!firstUserTurn?.content) {
    return 'New conversation';
  }

  return firstUserTurn.content.length > 36
    ? `${firstUserTurn.content.slice(0, 36)}...`
    : firstUserTurn.content;
}

function buildRenderedTurns(turns: AgentTurn[]) {
  const items: RenderedTurn[] = [];

  for (let index = 0; index < turns.length; index += 1) {
    const turn = turns[index];

    if (turn.role === 'tool_result') {
      continue;
    }

    if (turn.role === 'tool_call') {
      const nextTurn = turns[index + 1];
      const pairedResult = nextTurn?.role === 'tool_result' ? nextTurn : null;
      items.push({
        key: `${turn.timestamp}:${turn.tool_name ?? 'tool'}:${index}`,
        turn,
        resultTurn: pairedResult,
      });

      if (pairedResult) {
        index += 1;
      }
      continue;
    }

    items.push({
      key: `${turn.timestamp}:${turn.role}:${index}`,
      turn,
    });
  }

  return items;
}

export function AgentChat({ timelineId }: AgentChatProps) {
  const sessions = useAgentSessions(timelineId);
  const createSession = useCreateSession(timelineId);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [draft, setDraft] = useState('');
  const [composerError, setComposerError] = useState<string | null>(null);
  const hasAutoCreatedSessionRef = useRef(false);
  const bottomAnchorRef = useRef<HTMLDivElement | null>(null);

  const activeSession = useAgentSession(activeSessionId);
  const sendMessage = useSendMessage(activeSessionId);
  const cancelSession = useCancelSession(activeSessionId);
  const sessionOptions = useMemo(() => sessions.data ?? [], [sessions.data]);

  const voice = useAgentVoice({
    onError: (message) => {
      setComposerError(message);
    },
    onTranscription: (text) => {
      void handleSend(text);
    },
  });

  const renderedTurns = useMemo(
    () => buildRenderedTurns(activeSession.data?.turns ?? []),
    [activeSession.data?.turns],
  );
  const activeStatus = activeSession.data?.status;
  const isProcessing = activeStatus === 'processing' || activeStatus === 'continue';
  const showKillSwitch = activeStatus === 'processing' || activeStatus === 'continue';

  useEffect(() => {
    if (!sessionOptions.length) {
      setActiveSessionId((current) => (current && current.length > 0 ? current : null));
      return;
    }

    setActiveSessionId((current) => {
      if (current && sessionOptions.some((session) => session.id === current)) {
        return current;
      }

      return sessionOptions[0]?.id ?? null;
    });
  }, [sessionOptions]);

  useEffect(() => {
    if (
      hasAutoCreatedSessionRef.current
      || sessions.isLoading
      || createSession.isPending
      || sessionOptions.length > 0
    ) {
      return;
    }

    hasAutoCreatedSessionRef.current = true;
    createSession.mutate(undefined, {
      onError: () => {
        hasAutoCreatedSessionRef.current = false;
      },
      onSuccess: (session) => {
        setActiveSessionId(session.id);
      },
    });
  }, [createSession, sessionOptions.length, sessions.isLoading]);

  useEffect(() => {
    const anchor = bottomAnchorRef.current;
    if (!anchor) {
      return;
    }

    anchor.scrollIntoView({ behavior: 'smooth', block: 'end' });
  }, [renderedTurns, isProcessing, sendMessage.continuationNotice]);

  async function handleCreateSession() {
    setComposerError(null);
    const session = await createSession.mutateAsync();
    setActiveSessionId(session.id);
    setDraft('');
  }

  async function handleSend(rawText?: string) {
    const text = (rawText ?? draft).trim();
    if (!text) {
      return;
    }

    if (!activeSessionId) {
      setComposerError('Creating a conversation. Try again in a moment.');
      return;
    }

    setComposerError(null);
    await sendMessage.mutateAsync(text);
    if (rawText === undefined) {
      setDraft('');
    }
  }

  return (
    <Card className="flex h-full min-h-0 flex-col border-border/80 bg-background/95 shadow-xl backdrop-blur">
      <CardHeader className="gap-3 border-b border-border/70 px-4 py-4">
        <div className="flex items-center justify-between gap-3">
          <div className="min-w-0">
            <CardTitle className="flex items-center gap-2 text-base">
              <MessageSquareText className="h-4 w-4" />
              Timeline Agent
            </CardTitle>
            <p className="mt-1 text-xs text-muted-foreground">
              Chat with the editor, inspect tool calls, and queue follow-up work.
            </p>
          </div>

          <Button
            type="button"
            size="sm"
            variant="outline"
            className="shrink-0 gap-1.5"
            onClick={() => void handleCreateSession()}
            disabled={createSession.isPending}
          >
            <Plus className="h-3.5 w-3.5" />
            New
          </Button>
        </div>

        <Select value={activeSessionId ?? ''} onValueChange={setActiveSessionId} disabled={sessionOptions.length === 0}>
          <SelectTrigger className="h-9">
            <SelectValue placeholder="Select a conversation" />
          </SelectTrigger>
          <SelectContent>
            {sessionOptions.map((session) => (
              <SelectItem key={session.id} value={session.id}>
                {formatSessionLabel(session.turns)}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </CardHeader>

      <CardContent className="flex min-h-0 flex-1 flex-col gap-3 px-4 py-4">
        <ScrollArea className="min-h-0 flex-1 rounded-xl border border-border/70 bg-muted/20">
          <div className="flex min-h-full flex-col gap-3 px-3 py-3">
            {activeSession.isLoading && (
              <div className="flex items-center gap-2 rounded-xl border border-dashed border-border px-3 py-4 text-sm text-muted-foreground">
                <Loader2 className="h-4 w-4 animate-spin" />
                Loading conversation...
              </div>
            )}

            {!activeSession.isLoading && renderedTurns.length === 0 && (
              <div className="rounded-xl border border-dashed border-border px-4 py-5 text-sm text-muted-foreground">
                Ask for a timeline summary, move a clip, trim a source range, or queue a generation task.
              </div>
            )}

            {renderedTurns.map((item) => (
              <AgentChatMessage
                key={item.key}
                turn={item.turn}
                resultTurn={item.resultTurn}
              />
            ))}

            {(isProcessing || sendMessage.isPending) && (
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                <Loader2 className="h-4 w-4 animate-spin" />
                Agent is thinking...
              </div>
            )}

            <div ref={bottomAnchorRef} />
          </div>
        </ScrollArea>

        <div className="space-y-2">
          {(composerError || sendMessage.error?.message || sendMessage.continuationNotice) && (
            <div
              className={cn(
                'rounded-lg border px-3 py-2 text-sm',
                composerError || sendMessage.error
                  ? 'border-destructive/40 bg-destructive/10 text-destructive'
                  : 'border-border/70 bg-muted/50 text-muted-foreground',
              )}
            >
              {composerError ?? sendMessage.error?.message ?? sendMessage.continuationNotice}
            </div>
          )}

          <div className="rounded-xl border border-border/80 bg-card px-3 py-3">

// deno-lint-ignore-file
import { serve } from "https://deno.land/std@0.224.0/http/server.ts";
import Groq from "npm:groq-sdk@0.26.0";
import { NO_SESSION_RUNTIME_OPTIONS, withEdgeRequest } from "../_shared/edgeHandler.ts";
import { toErrorMessage } from "../_shared/errorMessage.ts";
