import type {
  AgentSession,
  AgentSessionStatus,
  AgentTurn,
} from "../../../src/tools/video-editor/types/agent-session.ts";
import type { AssetRegistry, TimelineConfig } from "../../../src/tools/video-editor/types/index.ts";

const GROQ_MODEL = "llama-3.3-70b-versatile";
const GROQ_FALLBACK_MODEL = "moonshotai/kimi-k2-instruct-0905";
const GROQ_TIMEOUT_MS = 30_000;
const LOOP_LIMIT = 8;
const SOFT_TIMEOUT_MS = 50_000;

let groqClient: Groq | null = null;

type TimelineState = {
  config: TimelineConfig;
  configVersion: number;
  registry: AssetRegistry;
  projectId: string;
};

type LlmMessage = {
  role: "system" | "user" | "assistant" | "tool";
  content: string | null;
  tool_call_id?: string;
  tool_calls?: Array<{
    id: string;
    type: "function";
    function: {
      name: string;
      arguments: string;
    };
  }>;
};

interface AgentInvocationBody {
  session_id?: unknown;
  user_message?: unknown;
}

interface TimelineRow {
  config: TimelineConfig;
  config_version: number;
  asset_registry: AssetRegistry;
  project_id: string;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function isSessionStatus(value: unknown): value is AgentSessionStatus {
  return value === "waiting_user"
    || value === "processing"
    || value === "continue"
    || value === "done"
    || value === "cancelled"
    || value === "error";
}

function normalizeTurns(value: unknown): AgentTurn[] {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.flatMap((item) => {
    if (!isRecord(item) || typeof item.content !== "string" || typeof item.timestamp !== "string") {
      return [];
    }

    const role = item.role;
    if (role !== "user" && role !== "assistant" && role !== "tool_call" && role !== "tool_result") {
      return [];
    }

    return [{
      role,
      content: item.content,
      tool_name: typeof item.tool_name === "string" ? item.tool_name : undefined,
      tool_args: isRecord(item.tool_args) ? item.tool_args : undefined,
      timestamp: item.timestamp,
    }];
  });
}

function createTurn(role: AgentTurn["role"], content: string): AgentTurn {
  return {
    role,
    content,
    timestamp: new Date().toISOString(),
  };
}

function createToolTurn(
  role: Extract<AgentTurn["role"], "tool_call" | "tool_result">,
  toolName: string,
  content: string,
  toolArgs: Record<string, unknown>,
): AgentTurn {
  return {
    role,
    content,
    tool_name: toolName,
    tool_args: toolArgs,
    timestamp: new Date().toISOString(),
  };
}

function normalizeSessionRow(row: Record<string, unknown>): AgentSession {
  return {
    id: typeof row.id === "string" ? row.id : "",
    timeline_id: typeof row.timeline_id === "string" ? row.timeline_id : "",
    user_id: typeof row.user_id === "string" ? row.user_id : "",
    status: isSessionStatus(row.status) ? row.status : "error",
    turns: normalizeTurns(row.turns),
    model: typeof row.model === "string" ? row.model : "groq",
    summary: typeof row.summary === "string" ? row.summary : null,
    created_at: typeof row.created_at === "string" ? row.created_at : "",
    updated_at: typeof row.updated_at === "string" ? row.updated_at : "",
  };
}

function normalizeTimelineRow(row: Record<string, unknown>): TimelineRow {
  return {
    config: (row.config as TimelineConfig | null) ?? { output: { resolution: "1920x1080", fps: 30, file: "output.mp4" }, clips: [] },
    config_version: typeof row.config_version === "number" ? row.config_version : 1,
    asset_registry: (row.asset_registry as AssetRegistry | null) ?? { assets: {} },
    project_id: typeof row.project_id === "string" ? row.project_id : "",
  };
}

function getGroqClient(): Groq {
  if (groqClient) {
    return groqClient;
  }

  const apiKey = Deno.env.get("GROQ_API_KEY");
  if (!apiKey) {
    throw new Error("[ai-timeline-agent] Missing GROQ_API_KEY");
  }

  groqClient = new Groq({ apiKey, timeout: GROQ_TIMEOUT_MS });
  return groqClient;
}

async function groqWithFallback(
  groq: Groq,
  params: Parameters<typeof groq.chat.completions.create>[0],
  logger: { info: (message: string, metadata?: Record<string, unknown>) => void },
) {
  try {
    return await groq.chat.completions.create(params);
  } catch (error: unknown) {
    const message = toErrorMessage(error);
    const shouldFallback = (
      message.includes("model")
      || message.includes("timeout")
      || message.includes("abort")
      || message.includes("could not process")
    ) && params.model !== GROQ_FALLBACK_MODEL;

    if (!shouldFallback) {
      throw error;
    }

    logger.info("Primary Groq model failed, retrying with fallback", {
      error: message,
      fallback_model: GROQ_FALLBACK_MODEL,
    });

    return await groq.chat.completions.create({
      ...params,
      model: GROQ_FALLBACK_MODEL,
    });
  }
}

function parseToolArgs(rawArguments: unknown): Record<string, unknown> {
  if (typeof rawArguments !== "string" || !rawArguments.trim()) {
    return {};
  }

  try {
    const parsed = JSON.parse(rawArguments);
    return isRecord(parsed) ? parsed : {};
  } catch {
    return {};
  }
}

function formatToolArgs(toolArgs: Record<string, unknown>): string {
  return JSON.stringify(toolArgs, null, 2);
}

function summarizeStoredToolTurn(turn: AgentTurn): string {
  const toolName = turn.tool_name ?? "tool";
  if (turn.role === "tool_call") {
    return `Tool call ${toolName}:\n${formatToolArgs(turn.tool_args ?? {})}`;
  }

  return `Tool result ${toolName}: ${turn.content}`;
}

function buildInitialMessages(
  systemPrompt: string,
  turns: AgentTurn[],
): LlmMessage[] {
  const messages: LlmMessage[] = [{ role: "system", content: systemPrompt }];

  for (const turn of turns) {
    if (turn.role === "user") {
      messages.push({ role: "user", content: turn.content });
      continue;
    }

    if (turn.role === "assistant") {
      messages.push({ role: "assistant", content: turn.content });
      continue;
    }

    messages.push({
      role: "assistant",
      content: summarizeStoredToolTurn(turn),
    });
  }

  return messages;
}

function extractAssistantText(message: { content?: unknown }): string {
  if (typeof message.content === "string") {
    return message.content.trim();
  }

  if (!Array.isArray(message.content)) {
    return "";
  }

  return message.content
    .flatMap((item) => {
      if (!isRecord(item)) {
        return [];
      }

      const text = item.text;
      return typeof text === "string" ? [text] : [];
    })
    .join("\n")
    .trim();
}

async function loadTimelineState(
  supabaseAdmin: {
    from: (table: string) => {
      select: (query: string) => {
        eq: (column: string, value: string) => {
          maybeSingle: () => Promise<{ data: unknown; error: { message: string } | null }>;
        };
      };
    };
  },
  timelineId: string,
): Promise<TimelineState> {
  const { data, error } = await supabaseAdmin
    .from("timelines")
    .select("config, config_version, asset_registry, project_id")
    .eq("id", timelineId)
    .maybeSingle();

  if (error) {
    throw new Error(`Failed to load timeline: ${error.message}`);
  }

  if (!data || !isRecord(data)) {
    throw new Error("Timeline not found");
  }

  const normalized = normalizeTimelineRow(data);
  return {
    config: normalized.config,
    configVersion: normalized.config_version,
    registry: normalized.asset_registry,
    projectId: normalized.project_id,
  };
}

async function saveTimelineConfigVersioned(
  supabaseAdmin: {
    rpc: (
      fn: string,
      args: Record<string, unknown>,
    ) => { maybeSingle: () => Promise<{ data: unknown; error: { message: string } | null }> };
  },
  timelineId: string,
  expectedVersion: number,
  config: TimelineConfig,
): Promise<number | null> {
  const { data, error } = await supabaseAdmin
    .rpc("update_timeline_config_versioned", {
      p_timeline_id: timelineId,
      p_expected_version: expectedVersion,
      p_config: config,
    })
    .maybeSingle();

  if (error) {
    throw new Error(`Failed to save timeline config: ${error.message}`);
  }

  const nextVersion = (data as { config_version?: unknown } | null)?.config_version;
  return typeof nextVersion === "number" ? nextVersion : null;
}

async function loadSessionStatus(
  supabaseAdmin: {
    from: (table: string) => {
      select: (query: string) => {
        eq: (column: string, value: string) => {
          maybeSingle: () => Promise<{ data: unknown; error: { message: string } | null }>;
        };
      };
    };
  },
  sessionId: string,
): Promise<AgentSessionStatus | null> {
  const { data, error } = await supabaseAdmin
    .from("timeline_agent_sessions")
    .select("status")
    .eq("id", sessionId)
    .maybeSingle();

  if (error || !data || !isRecord(data)) {
    return null;
  }

  return isSessionStatus(data.status) ? data.status : null;
}

async function persistSessionState(
  supabaseAdmin: {
    from: (table: string) => {
      update: (payload: Record<string, unknown>) => {
        eq: (column: string, value: string) => Promise<{ error: { message: string } | null }>;
      };
    };
  },
  options: {
    sessionId: string;
    status: AgentSessionStatus;
    turns: AgentTurn[];
    summary: string | null;
  },
): Promise<void> {
  const { error } = await supabaseAdmin
    .from("timeline_agent_sessions")
    .update({
      status: options.status,
      turns: options.turns,
      summary: options.summary,
      updated_at: new Date().toISOString(),
    })
    .eq("id", options.sessionId);

  if (error) {
    throw new Error(`Failed to persist session state: ${error.message}`);
  }
}

async function executeTimelineTool(
  toolName: keyof typeof timelineTools,
  toolArgs: Record<string, unknown>,
  state: TimelineState,
  timelineId: string,
  supabaseAdmin: {
    from: (table: string) => {
      select: (query: string) => {
        eq: (column: string, value: string) => {
          maybeSingle: () => Promise<{ data: unknown; error: { message: string } | null }>;
        };
      };
    };
    rpc: (
      fn: string,
      args: Record<string, unknown>,
    ) => { maybeSingle: () => Promise<{ data: unknown; error: { message: string } | null }> };
  },
): Promise<TimelineToolResult> {
  const runTool = () => timelineTools[toolName](state.config, state.registry, toolArgs);
  let result = runTool();

  if (!result.config) {
    return result;
  }

  let nextVersion = await saveTimelineConfigVersioned(
    supabaseAdmin,
    timelineId,
    state.configVersion,
    result.config,
  );

  if (nextVersion !== null) {
    state.config = result.config;
    state.configVersion = nextVersion;
    return result;
  }

  const refreshedState = await loadTimelineState(supabaseAdmin, timelineId);
  state.config = refreshedState.config;

  state.config = refreshedState.config;
  state.configVersion = refreshedState.configVersion;
  state.registry = refreshedState.registry;
  state.projectId = refreshedState.projectId;

  result = runTool();
  if (!result.config) {
    return {
      result: `${result.result} (retried after reload.)`,
    };
  }

  nextVersion = await saveTimelineConfigVersioned(
    supabaseAdmin,
    timelineId,
    state.configVersion,
    result.config,
  );

  if (nextVersion === null) {
    return {
      result: `Version conflict prevented applying ${toolName}. Please retry after the latest timeline reload.`,
    };
  }

  state.config = result.config;
  state.configVersion = nextVersion;
  return {
    ...result,
    result: `${result.result} (retried after reload.)`,
  };
}

serve((req) => withEdgeRequest<AgentInvocationBody>(
  req,
  {
    functionName: "ai-timeline-agent",
    logPrefix: "[AI-TIMELINE-AGENT]",
    method: "POST",
    parseBody: "strict",
    auth: {
      required: true,
      options: { allowJwtUserAuth: true },
    },
    ...NO_SESSION_RUNTIME_OPTIONS,
  },
  async ({ auth, body, logger, supabaseAdmin }) => {
    if (!auth?.userId) {
      return jsonResponse({ error: "Authentication failed" }, 401);
    }

    const sessionId = typeof body.session_id === "string" ? body.session_id.trim() : "";
    const userMessage = body.user_message === undefined || body.user_message === null
      ? undefined
      : typeof body.user_message === "string"
        ? body.user_message.trim()
        : null;

    if (!sessionId) {
      return jsonResponse({ error: "session_id is required" }, 400);
    }

    if (userMessage === null) {
      return jsonResponse({ error: "user_message must be a string when provided" }, 400);
    }

    const { data: rawSession, error: sessionError } = await supabaseAdmin
      .from("timeline_agent_sessions")
      .select("*")
      .eq("id", sessionId)
      .maybeSingle();

    if (sessionError) {
      logger.error("Failed to load session", {
        session_id: sessionId,
        error: sessionError.message,
      });
      return jsonResponse({ error: "Failed to load session" }, 500);
    }

    if (!rawSession || !isRecord(rawSession)) {
      return jsonResponse({ error: "Session not found" }, 404);
    }

    const session = normalizeSessionRow(rawSession);

    if (session.user_id !== auth.userId) {
      return jsonResponse({ error: "Forbidden" }, 403);
    }

    if (session.status === "cancelled") {
      return jsonResponse({ error: "Session cancelled", status: "cancelled" }, 409);
    }

    const turns = userMessage ? [...session.turns, createTurn("user", userMessage)] : [...session.turns];
    let status: AgentSessionStatus = "processing";
    let summary = session.summary;
    const turnsBeforeInvocation = session.turns.length;

    try {
      await persistSessionState(supabaseAdmin, {
        sessionId: session.id,
        status,
        turns,
        summary,
      });

      const timelineState = await loadTimelineState(supabaseAdmin, session.timeline_id);
      const timelineSummary = timelineTools.view_timeline(timelineState.config, timelineState.registry, {}).result;
      const systemPrompt = buildTimelineAgentSystemPrompt({
        projectId: timelineState.projectId,
        timelineSummary,
      });
      const messages = buildInitialMessages(systemPrompt, turns);
      const groq = getGroqClient();
      const startedAt = Date.now();

      loop: for (let iteration = 0; iteration < LOOP_LIMIT; iteration += 1) {
        if (Date.now() - startedAt >= SOFT_TIMEOUT_MS) {
          status = "continue";
          break;
        }

        const currentStatus = await loadSessionStatus(supabaseAdmin, session.id);
        if (currentStatus === "cancelled") {
          status = "cancelled";
          break;
        }

        const completion = await groqWithFallback(
          groq,
          {
            model: GROQ_MODEL,
            messages: messages as Parameters<typeof groq.chat.completions.create>[0]["messages"],
            tools: TIMELINE_AGENT_TOOLS as Parameters<typeof groq.chat.completions.create>[0]["tools"],
            tool_choice: "auto",
            temperature: 0.2,
            max_tokens: 4096,
            top_p: 1,
          },
          logger,
        );

        const responseMessage = completion.choices[0]?.message;
        if (!responseMessage) {
          turns.push(createTurn("assistant", "I couldn't produce a response."));
          status = "waiting_user";
          break;
        }

        const assistantText = extractAssistantText(responseMessage);
        const rawToolCalls = Array.isArray((responseMessage as { tool_calls?: unknown[] }).tool_calls)
          ? ((responseMessage as { tool_calls: unknown[] }).tool_calls as unknown[])
          : [];
        const toolCalls = rawToolCalls.flatMap((toolCall) => {
          if (!isRecord(toolCall)) {
            return [];
          }

          const fn = isRecord(toolCall.function) ? toolCall.function : undefined;
          if (!fn || typeof fn.name !== "string") {
            return [];
          }

          return [{
            id: typeof toolCall.id === "string" ? toolCall.id : crypto.randomUUID(),
            type: "function" as const,
            function: {
              name: fn.name,
              arguments: typeof fn.arguments === "string" ? fn.arguments : "{}",
            },
          }];
        });

        if (toolCalls.length === 0) {
          const text = assistantText || "I need a bit more direction before changing the timeline.";
          turns.push(createTurn("assistant", text));
          messages.push({ role: "assistant", content: text });
          status = "waiting_user";
          break;
        }

        messages.push({
          role: "assistant",
          content: assistantText || null,
          tool_calls: toolCalls,
        });

        for (const toolCall of toolCalls) {
          if (Date.now() - startedAt >= SOFT_TIMEOUT_MS) {
            status = "continue";
            break loop;
          }

          const currentStatusBeforeTool = await loadSessionStatus(supabaseAdmin, session.id);
          if (currentStatusBeforeTool === "cancelled") {
            status = "cancelled";
            break loop;
          }

          const toolName = toolCall.function.name;
          const toolArgs = parseToolArgs(toolCall.function.arguments);
          turns.push(createToolTurn(
            "tool_call",
            toolName,
            `Called ${toolName}.`,
            toolArgs,
          ));

          let toolResult:
            | TimelineToolResult
            | Awaited<ReturnType<(typeof sessionTools)[keyof typeof sessionTools]>>;

          if (toolName in timelineTools) {
            toolResult = await executeTimelineTool(
              toolName as keyof typeof timelineTools,
              toolArgs,
              timelineState,
              session.timeline_id,
              supabaseAdmin,
            );
          } else if (toolName in sessionTools) {
            const tool = sessionTools[toolName as keyof typeof sessionTools];
            if (toolName === "message_user") {
              toolResult = tool(typeof toolArgs.text === "string" ? toolArgs.text : "") as ReturnType<typeof sessionTools.message_user>;
            } else if (toolName === "done") {
              toolResult = tool(typeof toolArgs.summary === "string" ? toolArgs.summary : "") as ReturnType<typeof sessionTools.done>;
            } else {
              toolResult = await tool(toolArgs as never);
            }
          } else {
            toolResult = { result: `Unknown tool ${toolName}.` };
          }

          turns.push(createToolTurn("tool_result", toolName, toolResult.result, toolArgs));
          messages.push({
            role: "tool",
            tool_call_id: toolCall.id,
            content: toolResult.result,
          });

          if (toolName === "message_user" || toolName === "done") {
            turns.push(createTurn("assistant", toolResult.result));
          }

          if ("stopLoop" in toolResult && toolResult.stopLoop) {
            status = toolResult.nextStatus ?? "waiting_user";
            if (toolName === "done") {
              summary = toolResult.result;
            }
            break loop;
          }
        }
      }

      if (status === "processing") {
        status = "continue";
      }

      await persistSessionState(supabaseAdmin, {
        sessionId: session.id,
        status,
        turns,
        summary,
      });

      logger.info("Agent loop completed", {
        session_id: session.id,
        status,
        turns_added: turns.length - turnsBeforeInvocation,
        tool_count: TIMELINE_AGENT_TOOLS.length,
      });

      return jsonResponse({
        session_id: session.id,
        status,
        turns_added: turns.length - turnsBeforeInvocation,
        tool_count: TIMELINE_AGENT_TOOLS.length,
        model: session.model,
      });
    } catch (error: unknown) {
      logger.error("Agent loop failed", {
        session_id: session.id,
        error: toErrorMessage(error),
      });

      try {
        await persistSessionState(supabaseAdmin, {
          sessionId: session.id,
          status: "error",
          turns,
          summary,
        });
      } catch (persistError: unknown) {
        logger.error("Failed to persist error state", {
          session_id: session.id,
          error: toErrorMessage(persistError),
        });
      }

      return jsonResponse({
        error: "Failed to process timeline agent request",
        details: toErrorMessage(error),
      }, 500);
    }
  },
));
